1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type Customer = { yearsWithMHPCO: number };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
7	type Step = QuoteStep | ClaimStep;
8	type Scenario = { customer: Customer; steps: Step[] };
9	type Policy = { items: Item[]; remainingCap: number };
10	
11	const PROCESSING_FEE = 5;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
15	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
16	
17	const INSURANCE_VALUE: Record<string, number> = {
18	  sword: 1000,
19	  amulet: 600,
20	  staff: 800,
21	  potion: 400,
22	  rune: 250,
23	  moonstone: 250,
24	};
25	
26	const FIRST_INSURANCE_RATE = 0.1;
27	const CURSE_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_RATE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_THRESHOLD_YEARS = 2;
32	const FOLLOWUP_DISCOUNT_RATE = 0.15;
33	
34	const COMPONENT_BLOCK_SIZE = 3;
35	const COMPONENT_BLOCK_PRICE = 60;
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	const BASE_PREMIUM: Record<string, number> = {
39	  sword: 100,
40	  amulet: 60,
41	  staff: 80,
42	  potion: 40,
43	  rune: 25,
44	  moonstone: 25,
45	};
46	
47	const countByType = (items: Item[]): Record<string, number> => {
48	  const counts: Record<string, number> = {};
49	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
50	  return counts;
51	};
52	
53	const qualifiesForComponentBlock = (type: string, count: number): boolean =>
54	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
55	
56	const lineItemPrice = (type: string, count: number): number =>
57	  qualifiesForComponentBlock(type, count)
58	    ? COMPONENT_BLOCK_PRICE
59	    : BASE_PREMIUM[type] * count;
60	
61	const sumBasePremiums = (items: Item[]): number =>
62	  Object.entries(countByType(items))
63	    .reduce((total, [type, count]) => total + lineItemPrice(type, count), 0);
64	
65	const rateOf = (amount: number, rate: number, applies: boolean): number =>
66	  applies ? amount * rate : 0;
67	
68	const isCursed = (item: Item): boolean => item.cursed === true;
69	
70	const enchantmentAtLeast = (item: Item, threshold: number): boolean =>
71	  (item.enchantment ?? 0) >= threshold;
72	
73	const isHighlyEnchanted = (item: Item): boolean =>
74	  enchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
75	
76	const itemSurcharges = (items: Item[]): number =>
77	  items.reduce((sum, item) => {
78	    const base = BASE_PREMIUM[item.type];
79	    return sum
80	      + rateOf(base, CURSE_SURCHARGE_RATE, isCursed(item))
81	      + rateOf(base, HIGH_ENCHANTMENT_RATE, isHighlyEnchanted(item));
82	  }, 0);
83	
84	const isLoyalCustomer = (customer: Customer): boolean =>
85	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
86	
87	const isFollowupContract = (stepIndex: number): boolean => stepIndex > 0;
88	
89	const quotePremium = (items: Item[], customer: Customer, stepIndex: number): number => {
90	  const basePremium = sumBasePremiums(items);
91	  const surcharges = itemSurcharges(items);
92	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
93	  const loyaltyDiscount = rateOf(basePremium, LOYALTY_DISCOUNT_RATE, isLoyalCustomer(customer));
94	  const followupDiscount = rateOf(basePremium, FOLLOWUP_DISCOUNT_RATE, isFollowupContract(stepIndex));
95	  return Math.ceil(basePremium + surcharges + firstInsurance - loyaltyDiscount - followupDiscount + PROCESSING_FEE);
96	};
97	
98	const validateItems = (items: Item[]): void => {
99	  for (const item of items) {
100	    if (!(item.type in BASE_PREMIUM)) {
101	      throw new Error(`Unknown item type: ${item.type}`);
102	    }
103	  }
104	};
105	
106	const insuranceSum = (items: Item[]): number =>
107	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
108	
109	const reimbursableAmount = (item: Item, amount: number): number =>
110	  enchantmentAtLeast(item, CLAIM_HIGH_ENCHANTMENT_THRESHOLD)
111	    ? amount * CLAIM_HIGH_ENCHANTMENT_RATE
112	    : amount;
113	
114	const damagePayout = (damage: Damage, policy: Policy): number => {
115	  const item = policy.items.find((i) => i.type === damage.itemType)!;
116	  return reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
117	};
118	
119	const totalPayout = (incident: Incident, policy: Policy): number =>
120	  incident.damages.reduce((sum, dmg) => sum + damagePayout(dmg, policy), 0);
121	
122	const validateDamages = (policy: Policy, incident: Incident): void => {
123	  const policyCounts = countByType(policy.items);
124	  const damageCounts: Record<string, number> = {};
125	  for (const dmg of incident.damages) damageCounts[dmg.itemType] = (damageCounts[dmg.itemType] ?? 0) + 1;
126	  for (const [type, count] of Object.entries(damageCounts)) {
127	    if (count > (policyCounts[type] ?? 0)) {
128	      throw new Error(`Too many damages for item type: ${type}`);
129	    }
130	  }
131	};
132	
133	const processClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
134	  validateDamages(policy, incident);
135	  const payout = totalPayout(incident, policy);
136	  policy.remainingCap -= payout;
137	  return { payout, remainingCap: policy.remainingCap };
138	};
139	
140	const processQuote = (step: QuoteStep, customer: Customer, stepIndex: number): { policy: Policy; premium: number } => {
141	  validateItems(step.items);
142	  const policy: Policy = { items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER };
143	  return { policy, premium: quotePremium(step.items, customer, stepIndex) };
144	};
145	
146	export const runScenario = (input: unknown): unknown => {
147	  const scenario = input as Scenario;
148	  const policies: Policy[] = [];
149	  const results = scenario.steps.map((step, index) => {
150	    if (step.op === "quote") {
151	      const { policy, premium } = processQuote(step, scenario.customer, index);
152	      policies[index] = policy;
153	      return { premium };
154	    }
155	    return processClaim(policies[step.policy], step.incident);
156	  });
157	  return { results };
158	};
